const PROCESSING_FEE = 5;

type QuoteStep = { op: "quote"; items: Array<{ type: string }> };

type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<QuoteStep>;
};

const quotePremium = (step: QuoteStep): number => {
  if (step.items.length === 0) return PROCESSING_FEE;
  return 115;
};

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};
